"""Metrics computation for session-browser."""

def get_token_breakdown(conn):
    """Compute token breakdown by category."""
    row = conn.execute("""
        SELECT SUM(input_tokens) as total_input,
            SUM(output_tokens) as total_output,
            SUM(cached_input_tokens) as total_cached
        FROM sessions
    """).fetchone()
    return dict(row) if row else {}

def compute_derived_metrics(session_dict):
    """Compute derived metrics for a single session."""
    total = (session_dict.get('input_tokens', 0) +
             session_dict.get('output_tokens', 0) +
             session_dict.get('cached_input_tokens', 0))
    session_dict['total_tokens'] = total
    return session_dict

def get_model_distribution(conn):
    rows = conn.execute("SELECT model, COUNT(*) as count FROM sessions GROUP BY model").fetchall()
    return type('obj', (object,), {'distribution': [dict(r) for r in rows]})()

def get_agent_distribution(conn):
    rows = conn.execute("SELECT agent, COUNT(*) as count FROM sessions GROUP BY agent").fetchall()
    return [dict(r) for r in rows]

def compute_aggregate_metrics(conn):
    row = conn.execute("SELECT COUNT(*) as total_sessions, AVG(duration_seconds) as avg_duration FROM sessions").fetchone()
    return dict(row) if row else {}

/* Token bar styles */
.token-bar {
    height: 8px;
    border-radius: 4px;
    background: linear-gradient(90deg, #3b82f6, #8b5cf6);
}
.token-bar--input { background-color: #3b82f6; }
.token-bar--output { background-color: #10b981; }
.token-bar--cached { background-color: #f59e0b; }
.token-bar--cache-write { background-color: #6366f1; }

/* Progress bar base */
.progress-bar {
    width: 100%;
    height: 12px;
    background-color: #e5e7eb;
    border-radius: 6px;
    overflow: hidden;
}
.progress-bar__fill {
    height: 100%;
    transition: width 0.3s ease;
}

/* Stat cards */
.stat-card {
    background: white;
    border: 1px solid #e5e7eb;
    border-radius: 8px;
    padding: 16px;
}
